xpath.script:
(function() {
    var STORAGE_KEY = 'wl_page_agent_history';
    var LANG_SET = false;
    var TEXT_FIXED = false;
    var HISTORY_RESTORED = false;

    // Chinese → Indonesian text replacements
    var TEXT_MAP = {
        '输入新任务，详细描述步骤，回车提交': 'Tulis perintah... (contoh: pesan seblak)',
        '准备就绪': 'Siap',
        '等待任务开始...': 'Menunggu tugas...',
        '正在思考...': 'Sedang berpikir...',
        '正在执行...': 'Sedang menjalankan...',
        '任务完成': 'Tugas selesai',
        '任务已停止': 'Tugas dihentikan',
        '出现错误': 'Terjadi kesalahan',
    };

    function fixText() {
        if (TEXT_FIXED) return;
        // Fix placeholder
        var input = document.querySelector('[class*="_taskInput_"]');
        if (input) {
            for (var cn in TEXT_MAP) {
                if (input.placeholder === cn || input.getAttribute('placeholder') === cn) {
                    input.placeholder = TEXT_MAP[cn];
                }
            }
            // Force Indonesian placeholder regardless
            if (input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
            }
        }

        // Fix all text nodes in agent widget
        var wrapper = document.querySelector('[class*="_wrapper_"]');
        if (wrapper) {
            var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
            var node;
            while (node = walker.nextNode()) {
                var t = node.textContent.trim();
                for (var cn in TEXT_MAP) {
                    if (t === cn || t.includes(cn)) {
                        node.textContent = node.textContent.replace(cn, TEXT_MAP[cn]);
                    }
                }
            }
        }
        TEXT_FIXED = true;
    }

    function setupAgent() {
        var pa = window.pageAgent;
        if (!pa || pa.disposed) return false;

        // 1. Set language to Indonesian
        if (!LANG_SET) {
            try {
                pa.config.language = 'id-ID';
                if (pa.config.pageController && pa.config.pageController.config) {
                    pa.config.pageController.config.language = 'id-ID';
                }
                LANG_SET = true;
                console.log('[Page Agent] Language: id-ID');
            } catch(e) {}
        }

        // 2. Fix Chinese text → Indonesian
        fixText();

        // 3. Restore chat history
        if (!HISTORY_RESTORED) {
            try {
                var saved = sessionStorage.getItem(STORAGE_KEY);
                if (saved) {
                    var history = JSON.parse(saved);
                    if (Array.isArray(history) && history.length > 0) {
                        pa.history = history;
                        console.log('[Page Agent] Restored ' + history.length + ' messages');
                    }
                }
            } catch(e) {}
            HISTORY_RESTORED = true;
        }

        // 4. Save on new messages
        try {
            pa.addEventListener('message', function() {
                try {
                    if (pa.history && pa.history.length > 0) {
                        sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history));
                    }
                } catch(e) {}
            });
        } catch(e) {}

        // 5. Save before page unload
        window.addEventListener('beforeunload', function() {
            try {
                if (pa.history && pa.history.length > 0) {
                    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history));
                }
            } catch(e) {}
        });

        return true;
    }

    // Wait for pageAgent to initialize
    var attempts = 0;
    var checkInterval = setInterval(function() {
        attempts++;
        if (window.pageAgent) {
            if (setupAgent()) {
                clearInterval(checkInterval);
                // Re-fix text after a delay (agent UI may re-render)
                setTimeout(fixText, 1000);
                setTimeout(fixText, 3000);
                console.log('[Page Agent] Warung Lakku AI ready (Indonesian, styled, persisted)');
            }
        }
        // Also fix text on every check (UI may render late)
        fixText();
        if (attempts > 30) {
            clearInterval(checkInterval);
        }
    }, 500);

    // MutationObserver: fix text when agent UI re-renders
    var observer = new MutationObserver(function() {
        fixText();
    });
    if (document.body) {
        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
    }
    // Stop observing after 30 seconds
    setTimeout(function() { observer.disconnect(); }, 30000);
})();
